const poolItems=[{key:"plate-25-215-90-75",name:"压板25T",spec:"215×90×75",route:[{name:"铣床光面",qty:12},{name:"线切割外形",qty:10},{name:"加工中心钻孔",qty:9}],demands:[{order:"A订单",product:"液压快速换模系统25T",qty:12,due:"5月20日"},{order:"B订单",product:"液压快速换模系统25T",qty:12,due:"5月22日"},{order:"C订单",product:"液压快速换模系统25T",qty:12,due:"5月25日"}]},{key:"pin-25-45-145",name:"销轴25T",spec:"45×145",route:[{name:"车床加工-1",qty:12},{name:"车床加工-2",qty:8}],demands:[{order:"A订单",product:"液压快速换模系统25T",qty:12,due:"5月20日"},{order:"B订单",product:"液压快速换模系统25T",qty:12,due:"5月22日"}]},{key:"cylinder-25-235-190-135",name:"缸体25T",spec:"235×190×135",route:[{name:"铣床光面",qty:12},{name:"车床开粗1",qty:10},{name:"车床开粗2",qty:8},{name:"车床钻孔",qty:6},{name:"精车1",qty:5},{name:"车端面",qty:5},{name:"加工中心钻孔",qty:4}],demands:[{order:"A订单",product:"液压快速换模系统25T",qty:12,due:"5月20日"},{order:"B订单",product:"液压快速换模系统25T",qty:12,due:"5月22日"},{order:"D订单",product:"液压快速换模系统25T",qty:12,due:"5月28日"}]},{key:"base-25-235-190-135",name:"基座25T",spec:"235×190×135",route:[{name:"铣床光面",qty:12},{name:"锯床断料",qty:10},{name:"加工中心正面",qty:8},{name:"加工中心C1",qty:6},{name:"加工中心C2",qty:5},{name:"线切割T槽",qty:4},{name:"加工中心阀块孔",qty:4},{name:"抛光打磨",qty:3}],demands:[{order:"A订单",product:"液压快速换模系统25T",qty:12,due:"5月20日"},{order:"B订单",product:"液压快速换模系统25T",qty:12,due:"5月22日"},{order:"C订单",product:"液压快速换模系统25T",qty:12,due:"5月25日"}]},{key:"piston-25-85-87",name:"活塞25T",spec:"85×87",route:[{name:"车床开粗-1",qty:12},{name:"车床开粗-2",qty:12},{name:"车床精车-1",qty:10},{name:"车间精车-2",qty:8},{name:"钻孔",qty:8},{name:"攻牙",qty:6}],demands:[{order:"A订单",product:"液压快速换模系统25T",qty:12,due:"5月20日"},{order:"C订单",product:"液压快速换模系统25T",qty:12,due:"5月25日"}]},{key:"pin-25-45-140",name:"销轴25T",spec:"45×140",route:[{name:"车床加工-1",qty:9},{name:"车床加工-2",qty:7}],demands:[{order:"E订单",product:"液压快速换模系统25T",qty:10,due:"5月26日"}]}];
const filters=[{key:"all",label:"全部"},{key:"high",label:"高风险"},{key:"tight",label:"偏紧"},{key:"normal",label:"正常"}];
let state={selectedKey:"plate-25-215-90-75",filter:"all"};
function theoreticalDone(item){return Math.min(...item.route.map(step=>step.qty))}function startedQty(item){return Math.max(...item.route.map(step=>step.qty))}function wipQty(item){return Math.max(0,startedQty(item)-theoreticalDone(item))}function totalDemand(item){return item.demands.reduce((sum,demand)=>sum+demand.qty,0)}function bottleneck(item){const min=theoreticalDone(item);return item.route.find(step=>step.qty===min)}function risk(item){const done=theoreticalDone(item);const demand=totalDemand(item);const ratio=done/Math.max(1,demand);if(ratio<.35)return{key:"high",label:"高风险"};if(ratio<.75)return{key:"tight",label:"偏紧"};return{key:"normal",label:"正常"}}function selectedItem(){return poolItems.find(item=>item.key===state.selectedKey)||poolItems[0]}function visibleItems(){return poolItems.filter(item=>state.filter==="all"||risk(item).key===state.filter)}
function renderMetrics(){const highCount=poolItems.filter(item=>risk(item).key==="high").length;const totalDone=poolItems.reduce((sum,item)=>sum+theoreticalDone(item),0);const totalDemandQty=poolItems.reduce((sum,item)=>sum+totalDemand(item),0);const worst=[...poolItems].sort((a,b)=>theoreticalDone(a)/totalDemand(a)-theoreticalDone(b)/totalDemand(b))[0];const metrics=[{label:"公共池规格数",value:`${poolItems.length}组`,sub:"按半成品名称 + 规格拆分"},{label:"理论完成总量",value:`${totalDone}件`,sub:"来自必经工序最小值"},{label:"订单总需求",value:`${totalDemandQty}件`,sub:"需求关系，不是占用关系"},{label:"高风险池",value:`${highCount}组`,sub:`最紧：${worst.name} ${worst.spec}`}];document.querySelector("#metricGrid").innerHTML=metrics.map(metric=>`<div class="metric"><span>${metric.label}</span><strong>${metric.value}</strong><small>${metric.sub}</small></div>`).join("")}
function renderFilter(){const root=document.querySelector("#riskFilter");root.innerHTML=filters.map(filter=>`<button class="${filter.key===state.filter?"active":""}" data-filter="${filter.key}" type="button">${filter.label}</button>`).join("");root.querySelectorAll("button").forEach(button=>{button.addEventListener("click",()=>{state.filter=button.dataset.filter;render()})})}
function renderPoolBoard(){const maxQty=Math.max(...poolItems.flatMap(item=>item.route.map(step=>step.qty)));const rows=visibleItems().map(item=>{const done=theoreticalDone(item);const currentRisk=risk(item);const min=bottleneck(item).qty;const bars=item.route.map((step,index)=>{const h=Math.max(12,Math.round(step.qty/maxQty*44));const isBottleneck=step.qty===min;return`<div class="process-bar ${isBottleneck?"bottleneck":""}" title="${step.name}：${step.qty}"><i style="height:${h}px"></i><span>${index+1}</span></div>`}).join("");return`<article class="pool-row ${item.key===state.selectedKey?"active":""}" data-key="${item.key}"><div class="pool-name"><strong>${item.name}</strong><span>${item.spec}</span></div><div class="process-mini">${bars}</div><div class="num">${done}<small>理论完成</small></div><div class="num">${wipQty(item)}<small>在制</small></div><div class="num">${item.demands.length}<small>关联订单</small></div><span class="status ${currentRisk.key}">${currentRisk.label}</span></article>`}).join("");document.querySelector("#poolBoard").innerHTML=rows;document.querySelectorAll(".pool-row").forEach(row=>{row.addEventListener("click",()=>{state.selectedKey=row.dataset.key;render()})})}
function renderCompletionDetail(){const item=selectedItem();const done=theoreticalDone(item);const maxQty=Math.max(...item.route.map(step=>step.qty));const bottleneckName=bottleneck(item).name;const steps=item.route.map(step=>{const pct=Math.round(step.qty/maxQty*100);const isBottleneck=step.name===bottleneckName;return`<div class="step-row ${isBottleneck?"bottleneck":""}"><strong>${step.name}</strong><div class="step-track"><span style="width:${pct}%"></span></div><em>${step.qty}</em></div>`}).join("");document.querySelector("#completionDetail").innerHTML=`<div class="selected-summary"><h4>${item.name} · ${item.spec}</h4><p>理论完成量取各必经工序最小值：${done}。当前卡点是 ${bottleneckName}。</p></div><div class="step-list">${steps}</div>`}
function renderDemandDetail(){const item=selectedItem();const cards=item.demands.map(demand=>`<article class="demand-card"><strong>${demand.order} · ${demand.product}</strong><span>需求 ${demand.qty} 件 · 交付日期 ${demand.due}</span></article>`).join("");document.querySelector("#demandDetail").innerHTML=`<div class="selected-summary"><h4>${item.name} · ${item.spec}</h4><p>总需求 ${totalDemand(item)} 件；以下只是需求关系，不代表公共池产出已经被这些订单占用。</p></div><div class="demand-list">${cards}</div>`}
function node(x,y,w,h,title,sub,id,type,active){const fill=type==="pool"?"#dff2ef":"#e1eefb";const stroke=active?"#14212b":"#d7e0e7";return`<g class="rel-node" data-id="${id}"><rect x="${x}" y="${y}" width="${w}" height="${h}" fill="${fill}" stroke="${stroke}"></rect><text x="${x+12}" y="${y+25}">${title}</text><text class="sub" x="${x+12}" y="${y+45}">${sub}</text></g>`}function curvedPath(x1,y1,x2,y2){const c1=x1+(x2-x1)*.5;const c2=x1+(x2-x1)*.5;return`M ${x1} ${y1} C ${c1} ${y1}, ${c2} ${y2}, ${x2} ${y2}`}
function renderRelationship(){const svg=document.querySelector("#relationshipSvg");const itemNodes=poolItems.map((item,index)=>({id:item.key,x:38,y:35+index*76,w:230,h:56,title:item.name,sub:`${item.spec} · 理论完成 ${theoreticalDone(item)}`}));const orders=[];poolItems.forEach(item=>{item.demands.forEach(demand=>{const id=`${demand.order}-${demand.product}`;if(!orders.some(order=>order.id===id)){orders.push({id,...demand})}})});const orderNodes=orders.map((order,index)=>({id:order.id,x:860,y:38+index*58,w:260,h:48,title:order.order,sub:`${order.product} · ${order.due}`}));const activeItem=selectedItem();const links=[];poolItems.forEach(item=>{item.demands.forEach(demand=>{const orderId=`${demand.order}-${demand.product}`;const from=itemNodes.find(n=>n.id===item.key);const to=orderNodes.find(n=>n.id===orderId);links.push({active:item.key===state.selectedKey,d:curvedPath(from.x+from.w,from.y+from.h/2,to.x,to.y+to.h/2)})})});svg.innerHTML=`<text x="40" y="22" fill="#667483" font-size="12" font-weight="800">半成品公共池</text><text x="862" y="22" fill="#667483" font-size="12" font-weight="800">订单需求</text>${links.map(link=>`<path class="rel-link ${link.active?"active":""}" d="${link.d}" stroke-width="${link.active?5:2}"></path>`).join("")}${itemNodes.map(n=>node(n.x,n.y,n.w,n.h,n.title,n.sub,n.id,"pool",n.id===state.selectedKey)).join("")}${orderNodes.map(n=>{const active=activeItem.demands.some(demand=>`${demand.order}-${demand.product}`===n.id);return node(n.x,n.y,n.w,n.h,n.title,n.sub,n.id,"order",active)}).join("")}`;svg.querySelectorAll(".rel-node").forEach(n=>{n.addEventListener("click",()=>{if(poolItems.some(item=>item.key===n.dataset.id)){state.selectedKey=n.dataset.id;render()}})})}
function render(){renderMetrics();renderFilter();renderPoolBoard();renderCompletionDetail();renderDemandDetail();renderRelationship()}render();
